import { cva, type VariantProps } from 'class-variance-authority';
import type { HTMLAttributes } from 'react';
import { cn } from '@/lib/utils';

/* Console 26: pill chip, uppercase micro-label, soft tints.
   nc-ui-badge--<variant> companions are styled in module components.css for
   ANCHOR-rendered badges only — BS4 Reboot's unlayered `a { color; … }`
   otherwise beats these layered color utilities on badge links. */
const badgeVariants = cva(
  'nc-ui-badge inline-flex items-center gap-1.5 rounded-full border px-2 py-0.5 text-[0.6875rem] font-bold uppercase tracking-wide transition-colors focus:outline-none focus:ring-2 focus:ring-[var(--oe-nc-primary)] focus:ring-offset-2',
  {
    variants: {
      variant: {
        default:   'nc-ui-badge--default border-transparent bg-[var(--oe-nc-primary)] text-white',
        success:   'nc-ui-badge--success border-[#a9d6c4] bg-[#e9f5f0] text-[#045d44]',
        warning:   'nc-ui-badge--warning border-[#ecd1ae] bg-[#faf1e4] text-[#8f3c06]',
        danger:    'nc-ui-badge--danger border-[#ecc3bf] bg-[#f9ecea] text-[#8f1c13]',
        info:      'nc-ui-badge--info border-[#b7d5f4] bg-[var(--oe-nc-primary-tint,#e8f1fc)] text-[var(--oe-nc-primary,#0071e3)]',
        neutral:   'nc-ui-badge--neutral border-[#d5d5d9] bg-[#ececef] text-[#48484c]',
        outline:   'nc-ui-badge--outline border-[var(--oe-nc-border)] text-[var(--oe-nc-text)]',
      },
    },
    defaultVariants: { variant: 'default' },
  }
);

export interface BadgeProps extends HTMLAttributes<HTMLSpanElement>, VariantProps<typeof badgeVariants> {}

export function Badge({ className, variant, ...props }: BadgeProps) {
  return <span className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { badgeVariants };
